arguments.command:
cd ~/.openclaw/workspace && cat > /tmp/params.json << 'EOF'
{"codes":"300033.SZ,600030.SH"}
EOF
node -e "
const fs=require('fs');
const params=fs.readFileSync('/tmp/params.json','utf8');
const args=JSON.parse(params);
const API_KEY=process.env.QVERIS_API_KEY;
const API_BASE='https://qveris.ai/api/v1';
// First search for the tool to get a proper search_id
fetch(\`\${API_BASE}/search\`,{
  method:'POST',
  headers:{'Content-Type':'application/json','Authorization':\`Bearer \${API_KEY}\`},
  body:JSON.stringify({query:'ths ifind realtime quotation',limit:1})
}).then(r=>r.json()).then(searchResult=>{
  console.log('Search result:',JSON.stringify(searchResult,null,2));
  const searchId = searchResult.results?.[0]?.id;
  console.log('Search ID:',searchId);
  // Now try execute with the search_id
  return fetch(\`\${API_BASE}/tools/execute\`,{
    method:'POST',
    headers:{'Content-Type':'application/json','Authorization':\`Bearer \${API_KEY}\`},
    body:JSON.stringify({tool_id:'ths_ifind.real_time_quotation.v1',params:args,search_id:searchId})
  });
}).then(r=>r.json()).then(d=>console.log(JSON.stringify(d,null,2))).catch(e=>console.error(e));
"

